--
-- Table structure for table `alignment_rows`
--

DROP TABLE IF EXISTS `alignment_rows`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `alignment_rows` (
  `id` char(36) NOT NULL DEFAULT uuid(),
  `program_id` char(36) NOT NULL,
  `group_label` text NOT NULL,
  `title` text NOT NULL,
  `description` text DEFAULT NULL,
  `sort_order` int(11) NOT NULL DEFAULT 0,
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_alignment_rows_prog` (`program_id`,`sort_order`),
  CONSTRAINT `fk_ar_prog` FOREIGN KEY (`program_id`) REFERENCES `programs` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

