INSERT INTO `alignment_rows` VALUES ('677d5bf1-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','Vision','Vision (ระดับมหาวิทยาลัย)','มหาวิทยาลัยแห่งคุณค่าเพื่อขับเคลื่อนการพัฒนาที่ยั่งยืนระดับแนวหน้าของโลก',35,'2026-03-24 11:53:30'),('677d7f13-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','Vision','Vision (ระดับคณะ)','สถาบันการศึกษาชั้นนำระดับประเทศด้านการจัดการ',36,'2026-03-24 11:53:30'),('677da172-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','Mission','Mission 1 (ระดับมหาวิทยาลัย)','สร้างความเป็นผู้นำทางวิชาการและนวัตกรรม โดยมีการวิจัยเป็นฐาน เพื่อการพัฒนาภาคใต้และประเทศ เชื่อมโยงสู่สังคมและเครือข่ายสากล',37,'2026-03-24 11:53:30'),('677dbd9a-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','Mission','Mission 2 (ระดับมหาวิทยาลัย)','สร้างทรัพยากรมนุษย์ที่มีสมรรถนะทางวิชาการและวิชาชีพ ซื่อสัตย์ มีวินัย ใฝ่ปัญญา และมีทักษะในศตวรรษที่ 21 สามารถประยุกต์ความรู้บนพื้นฐานประสบการณ์จากการปฏิบัติ',38,'2026-03-24 11:53:30'),('677ddd86-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','Mission','Mission 3 (ระดับมหาวิทยาลัย)','พัฒนามหาวิทยาลัยให้เป็นสังคมฐานความรู้บนพื้นฐานพหุวัฒนธรรมและหลักปรัชญาของเศรษฐกิจพอเพียง เพื่อการพัฒนาสู่ความยั่งยืนและร่วมสร้างสังคมแห่ง โอกาสและความเป็นธรรม',39,'2026-03-24 11:53:30'),('677dfc3c-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','Mission','Mission 1 (ระดับคณะ)','สร้างบัณฑิต นักบริหาร และผู้ประกอบการที่มีภาวะผู้นำ มีสมรรถนะดิจิทัล มีความคิดสร้างสรรค์ เพื่อประโยชน์ของเพื่อนมนุษย์ ด้วยหลักสูตรที่ได้รับรองมาตรฐานสากล',40,'2026-03-24 11:53:30'),('677e1ada-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','Identity','อัตลักษณ์ของมหาวิทยาลัย (GE)','ผลการเรียนรู้ของหมวดวิชาศึกษาทั่วไป',41,'2026-03-24 11:53:30'),('677e342a-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','Stakeholder Need 1 : ผู้ใช้บัณฑิต','คิดวิเคราะห์','',42,'2026-03-24 11:53:30'),('677e4c42-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','Stakeholder Need 1 : ผู้ใช้บัณฑิต','คิดอย่างเป็นระบบ','',43,'2026-03-24 11:53:30'),('677e66c6-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','Stakeholder Need 1 : ผู้ใช้บัณฑิต','การวิเคราะห์ข้อมูล (Data Analysis)','',44,'2026-03-24 11:53:30'),('677e8087-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','Stakeholder Need 1 : ผู้ใช้บัณฑิต','การคิดเชิงบวก (Growth Mindset)','',45,'2026-03-24 11:53:30'),('677e9895-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','Stakeholder Need 1 : ผู้ใช้บัณฑิต','การเป็นผู้ประกอบการ','',46,'2026-03-24 11:53:30'),('677eb0e8-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','Stakeholder Need 1 : ผู้ใช้บัณฑิต','การแก้ปัญหา','',47,'2026-03-24 11:53:30'),('677ec95e-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','Stakeholder Need 1 : ผู้ใช้บัณฑิต','ความรับผิดชอบต่อสังคม','',48,'2026-03-24 11:53:30'),('677edff7-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','Stakeholder Need 2 : ศิษย์เก่า','การสื่อสาร/ภาษาที่ 3','',49,'2026-03-24 11:53:30'),('677ef7cc-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','Stakeholder Need 2 : ศิษย์เก่า','ก้าวทันเทคโนโลยี','',50,'2026-03-24 11:53:30'),('677f0f93-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','Stakeholder Need 2 : ศิษย์เก่า','ภาวะผู้นำ','',51,'2026-03-24 11:53:30'),('677f2c7d-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','Stakeholder Need 2 : ศิษย์เก่า','การวิเคราะห์ข้อมูล (Data Analysis)','',52,'2026-03-24 11:53:30'),('6780021f-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','Stakeholder Need 2 : ศิษย์เก่า','ความรับผิดชอบต่อสังคม','',53,'2026-03-24 11:53:30'),('67801aee-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','Stakeholder Need 3 : ศิษย์ปัจจุบัน','การสื่อสาร/ภาษาที่ 3','',54,'2026-03-24 11:53:30'),('678032af-273d-11f1-9355-00090ffe0001','