--
-- Table structure for table `major_subjects`
--

DROP TABLE IF EXISTS `major_subjects`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `major_subjects` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `major_id` int(11) NOT NULL,
  `subject_code` varchar(20) NOT NULL,
  `name_th` varchar(300) NOT NULL,
  `name_en` varchar(300) NOT NULL DEFAULT '',
  `credits` varchar(10) NOT NULL DEFAULT '3',
  `credit_detail` varchar(30) NOT NULL DEFAULT '',
  `subject_type` enum('required','elective') NOT NULL DEFAULT 'required',
  `special_note` varchar(300) NOT NULL DEFAULT '',
  `sort_order` smallint(5) unsigned NOT NULL DEFAULT 0,
  `is_active` tinyint(1) NOT NULL DEFAULT 1,
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  `updated_at` datetime NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_ms_code_per_major` (`major_id`,`subject_code`),
  CONSTRAINT `fk_ms_major` FOREIGN KEY (`major_id`) REFERENCES `majors` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=311 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

