INSERT INTO `majors` VALUES (1,3,'วิชาเอกการเงินและการลงทุน','Finance and Investment','ศึกษาเกี่ยวกับการบริหารการเงิน หลักการลงทุน การบริหารสินเชื่อ การวิเคราะห์หลักทรัพย์ การบริหารสถาบันการเงิน การเงินระหว่างประเทศ การบริหารโครงการธุรกิจ','https://res.cloudinary.com/dm2kfq5en/image/upload/v1774108206/fms-uploads/huchxgocxnbvtqcs70po.jpg','พนักงานการเงิน\nนักวิเคราะห์การเงิน\nนักวิชาการเงินและพัสดุ\nผู้ประกอบวิชาชีพในธุรกิจหลักทรัพย์\nนักบริหารการเงินในองค์กรเอกชนและภาครัฐ\nนักบริหารการเงินในตลาดเงิน\nนักบริหารการเงินในตลาดทุน\nอาชีพอิสระ','https://res.cloudinary.com/dm2kfq5en/image/upload/v1774108186/fms-uploads/daa8zn9ldu1onwigbiwt.jpg','YEAR 1: พื้นฐานธุรกิจและความรู้รอบด้าน\n- พื้นฐานด้าน บริหารธุรกิจ ทั้งระบบ\n- ความรู้ทั่วไป (GE) เพื่อพัฒนาทักษะชีวิต','YEAR 2: ความรู้พื้นฐาน\n- เรียนเกี่ยวกับกระบวนการทำงาน\n- ความรู้เบื้องต้นของวิชาเอก\n- เรียนวิชาเลือก/วิชาโท','YEAR 3: ความเชี่ยวชาญเฉพาะด้าน\n- เรียนเชิงลึกตามสายวิชา\n- การฝึกงานภาคฤดูร้อน','YEAR 4: การบูรณาการ\n- เรียนการเชื่อมโยงองค์ความรู้\n- โครงงานแต่ละวิชาเอก\n- การฝึกงานสหกิจ','2026-03-14 13:24:37'),(2,3,'วิชาเอกการตลาดและการสื่อสาร','Marketing and Communication','ศึกษาเกี่ยวกับการบริหารการตลาด พฤติกรรมผู้บริโภค การวิเคราะห์เชิงปริมาณสำหรับการตลาด กลยุทธ์การส่งเสริมการตลาด การตลาดสินค้าระหว่างประเทศ กลยุทธ์การตลาดดิจิทัล','https://res.cloudinary.com/dm2kfq5en/image/upload/v1774108170/fms-uploads/ciyoabcbxmorrjflf4sb.jpg','เจ้าหน้าที่การตลาด\nนักวิจัยตลาด\nเจ้าหน้าที่ด้านการส่งออก-นำเข้า\nผู้จัดการธุรกิจขายตรง\nตัวแทนขาย\nพนักงานขาย\nพนักงานลูกค้าสัมพันธ์\nอาชีพอิสระ','https://res.cloudinary.com/dm2kfq5en/image/upload/v1774108152/fms-uploads/bon0fqtt1zndiw5js6vh.jpg','YEAR 1: พื้นฐานธุรกิจและความรู้รอบด้าน\n- พื้นฐานด้าน บริหารธุรกิจ ทั้งระบบ\n- ความรู้ทั่วไป (GE) เพื่อพัฒนาทักษะชีวิต','YEAR 2: ความรู้พื้นฐาน\n- เรียนเกี่ยวกับกระบวนการทำงาน\n- ความรู้เบื้องต้นของวิชาเอก\n- เรียนวิชาเลือก/วิชาโท','YEAR 3: ความเชี่ยวชาญเฉพาะด้าน\n- เรียนเชิงลึกตามสายวิชาเอก\n- การฝึกงานภาคฤดูร้อน','YEAR 4: การบูรณาการ\n- เรียนการเชื่อมโยงองค์ความรู้\n- โครงงานแต่ละวิชาเอก\n- การฝึกงานสหกิจ','2026-03-14 13:24:37'),(3,3,'วิชาเอกการจัดการทรัพยากรมนุษย์','Human Resource Management','ศึกษาเกี่ยวกับการบริหารทรัพยากรมนุษย์ การวางแผนอัตรากำลัง การพัฒนาทรัพยากรมนุษย์และองค์กร การเจรจาต่อรองทางธุรกิจ กฎหมายเกี่ยวกับการบริหารทรัพยากรมนุษย์','https://res.cloudinary.com/dm2kfq5en/image/upload/v1774108129/fms-uploads/iihkxfnvurd60l07ovga.jpg','เจ้าหน้าที่ฝ่ายบุคคล\nเจ้าหน้าที่สรรหา\nพนักงานบริการลูกค้า\nเลขานุการ\nเจ้าหน้าที่บริหารงานทั่วไป\nอาชีพอิสระ','https://res.cloudinary.com/dm2kfq5en/image/upload/v1774108122/fms-uploads/xgepdirkimcqtktl32tf.jpg','YEAR 1: พื้นฐานธุรกิจและความรู้รอบด้าน\n- พื้นฐานด้าน บริหารธุรกิจ ทั้งระบบ\n- ความรู้ทั่วไป (GE) เพื่อพัฒนาทักษะชีวิต','YEAR 2: ความรู้พื้นฐาน\n- เรียนเกี่ยวกับกระบวนการทำงาน\n- ความรู้เบื้องต้นของวิชาเอก\n- เรียนวิชาเลือก/วิชาโท','YEAR 3: ความเชี่ยวชาญเฉพาะด้าน\n- เรียนเชิงลึกตามสายวิชา\n- การฝึกงานภาคฤดูร้อน','YEAR 4: การบูรณาการ\n- เรียนการเชื่อมโยงองค์ความรู้\n- โครงงานแต่ละวิชาเอก\n- การฝึกงานสหกิจ','2026-03-14 13:24:37'),(4,3,'วิชาเอกการจัดการโลจิสติกส์และโซ่อุปทาน','Logistics and Supply Chain Management','ศึกษาเกี่ยวกับการจัดการโลจิสติกส์และโซ่อุปทาน การวิเคราะห์เชิงปริมาณสำหรับการจัดการโลจิสติกส์ การขนส่งและการกระจายสินค้า การวางแผนอุปสงค์และสินค้าคงคลัง','https://res.cloudinary.com/dm2kfq5en/image/upload/v1774108107/fms-uploads/byvgx2bfelqkdlf4b3qu.jpg','เจ้าหน้าที่ฝ่ายบุคคล\nเจ้าหน้าที่สรรหา\nพนักงานบริการลูกค้า\nเลขานุการ\nเจ้าหน้าที่บริหารงานทั่วไป\nอาชีพอิสระ','https://res.cloudinary.com/dm2kfq5en/image/upload/v1774108104/fms-uploads/fwabvo6hbcmeqv5ey5or.jpg','YEAR 1: พื้นฐานธุรกิจและความรู้รอบด้าน\n- พื้นฐานด้าน บริหารธุรกิจ ทั้งระบบ\n- ความรู้ทั่วไป (GE) เพื่อพัฒนาทักษะชีวิต','YEAR 2: ความรู้พื้นฐาน\n- เรียนเกี่ยวกับกระบวนการทำงาน\n- ความรู้เบื้องต้นของวิชาเอก\n- เรียนวิชาเลือก/วิชาโท','YEAR 3: ความเชี่ยวชาญเฉพาะด้าน\n- เรียนเชิงลึกตามสายวิชา\n- การฝึกงานภาคฤดูร้อน','YEAR 4: การบูรณาการ\n- เรียนการเชื่อมโยงองค์ความรู้\n- โครงงานแต่ละวิชาเอก\n- การฝึกงานสหกิจ','2026-03-14 13:24:37'),(5,3,'วิชาเอกระบบสารสนเทศทางธุรกิจ','Business Information Systems','ศึกษาเกี่ยวกับพื้นฐานระบบสารสนเทศ การเขียนโปรแกรมคอมพิวเตอร์ การสื่อสารข้อมูลและเครือข่ายคอมพิวเตอร์ การบริหารโครงการทางเทคโนโลยีสารสนเทศ ระบบสารสนเทศเพื่อการจัดการ','https://res.cloudinary.com/dm2kfq5en/image/upload/v1774108081/fms-uploads/lm4mhjbftbowfdf7g30j.jpg','เจ้าหน้าที่สนับสนุนการใช้เทคโนโลยีสารสนเทศในองค์กร\nเจ้าหน้าที่ดูแลระบบ\nโปรแกรมเมอร์\nนักออกแบบส่วนติดต่อผู้ใช้\nเจ้าหน้าที่ออกแบบและบริหารระบบสารสนเทศในองค์กร\nผู้บริหารเว็บไซต์\nผู้บริหารระบบสารสนเทศ\nอาชีพอิสระ','https://res.cloudinary.com/dm2kfq5en/image/upload/v1774108078/fms-uploads/wunlgwdo937clzd8nyhh.jpg','YEAR 1: พื้นฐานธุรกิจและความรู้รอบด้าน\n- พื้นฐานด้าน บริหารธุรกิจ ทั้งระบบ\n- ความรู้ทั่วไป (GE) เพื่อพัฒนาทักษะชีวิต','YEAR 2: ความรู้พื้นฐาน\n- เรียนเกี่ยวกับกระบวนการทำงาน\n- ความรู้เบื้องต้นของวิชาเอก\n- เรียนวิชาเลือก/วิชาโท','YEAR 3: ความเชี่ยวชาญเฉพาะด้าน\n- เรียนเชิงลึกตามสายวิชา\n- การฝึกงานภาคฤดูร้อน','YEAR 4: การบูรณาการ\n- เรียนการเชื่อมโยงองค์ความรู้\n- โครงงานแต่ละวิชาเอก\n- การฝึกงานสหกิจ','2026-03-14 13:24:37'),(6,3,'วิชาเอกการจัดการไมซ์','MICE Management','ศึกษาเกี่ยวกับความรู้เบื้องต้นในอุตสาหกรรมไมซ์ การจัดการประชุมและการท่องเที่ยวเพื่อเป็นรางวัล ความรู้เบื้องต้นในอุตสาหกรรมท่องเที่ยว การจัดการนิทรรศการ','https://res.cloudinary.com/dm2kfq5en/image/upload/v1774108062/fms-uploads/he1mvfgbyoxwo4umalek.jpg','เจ้าหน้าที่ฝ่ายบุคคล\nเจ้าหน้าที่สรรหา\nพนักงานบริการลูกค้า\nเลขานุการ\nเจ้าหน้าที่บริหารงานทั่วไป\nอาชีพอิสระ','https://res.cloudinary.com/dm2kfq5en/image/upload/v1774108053/fms-uploads/ie9velwqvtq0ncak6dtx.jpg','YEAR 1: พื้นฐานธุรกิจและความรู้รอบด้าน\n- พื้นฐานด้าน บริหารธุรกิจ ทั้งระบบ\n- ความรู้ทั่วไป (GE) เพื่อพัฒนาทักษะชีวิต','YEAR 2: ความรู้พื้นฐาน\n- เรียนเกี่ยวกับกระบวนการทำงาน\n- ความรู้เบื้องต้นของวิชาเอก\n- เรียนวิชาเลือก/วิชาโท','YEAR 3: ความเชี่ยวชาญเฉพาะด้าน\n- เรียนเชิงลึกตามสายวิชา\n- การฝึกงานภาคฤดูร้อน','YEAR 4: การบูรณาการ\n- เรียนการเชื่อมโยงองค์ความรู้\n- โครงงานแต่ละวิชาเอก\n- การฝึกงานสหกิจ','2026-03-14 13:24:37'),(14,5,'วิชาเอกระบบสารสนเทศทางธุรกิจ','Business Information Systems','ศึกษาเกี่ยวกับพื้นฐานระบบสารสนเทศ การเขียนโปรแกรมคอมพิวเตอร์ การสื่อสารข้อมูลและเครือข่ายคอมพิวเตอร์ การบริหารโครงการทางเทคโนโลยีสารสนเทศ ระบบสารสนเทศเพื่อการจัดการ','https://res.cloudinary.com/dm2kfq5en/image/upload/v1774107753/fms-uploads/u77mc38tqtra3wkiykvu.jpg','เจ้าหน้าที่สนับสนุนการใช้เทคโนโลยีสารสนเทศในองค์กร\nเจ้าหน้าที่ดูแลระบบ\nโปรแกรมเมอร์\nนักออกแบบส่วนติดต่อผู้ใช้\nเจ้าหน้าที่ออกแบบและบริหารระบบสารสนเทศในองค์กร\nผู้บริหารเว็บไซต์\nผู้บริหารระบบสารสนเทศ\nอาชีพอิสระ','https://res.cloudinary.com/dm2kfq5en/image/upload/v1774107751/fms-uploads/zodlziffqf0vnetjgtra.jpg','YEAR 1: พื้นฐานธุรกิจและความรู้รอบด้าน\n- พื้นฐานด้าน บริหารธุรกิจ ทั้งระบบ\n- ความรู้ทั่วไป (GE) เพื่อพัฒนาทักษะชีวิต','YEAR 2: ความรู้พื้นฐาน\n- เรียนเกี่ยวกับกระบวนการทำงาน\n- ความรู้เบื้องต้นของวิชาเอก\n- เรียนวิชาเลือก/วิชาโท','YEAR 3: ความเชี่ยวชาญเฉพาะด้าน\n- เรียนเชิงลึกตามสายวิชา\n- การฝึกงานภาคฤดูร้อน','YEAR 4: การบูรณาการ\n- เรียนการเชื่อมโยงองค์ความรู้\n- โครงงานแต่ละวิชาเอก\n- การฝึกงานสหกิจ','2026-03-14 13:26:15'),(15,5,'วิชาเอกการเงินและการลงทุน','Finance and Investment','ศึกษาเกี่ยวกับการบริหารการเงิน หลักการลงทุน การบริหารสินเชื่อ การวิเคราะห์หลักทรัพย์ การบริหารสถาบันการเงิน การเงินระหว่างประเทศ การบริหารโครงการธุรกิจ สัมมนาทางการเงิน','https://res.cloudinary.com/dm2kfq5en/image/upload/v1773567264/fms-uploads/jlfx3pynn4bxmttbguur.jpg','พนักงานการเงิน\nนักวิเคราะห์การเงิน\nนักวิชาการเงินและพัสดุ\nผู้ประกอบวิชาชีพในธุรกิจหลักทรัพย์\nนักบริหารการเงินในองค์กรเอกชนและภาครัฐ\nนักบริหารการเงินในตลาดเงิน\nนักบริหารการเงินในตลาดทุน\nอาชีพอิสระ','https://res.cloudinary.com/dm2kfq5en/image/upload/v1773567265/fms-uploads/ildfit5iwyk0qnc7pdnl.jpg','YEAR 1: พื้นฐานธุรกิจและความรู้รอบด้าน\n- พื้นฐานด้าน บริหารธุรกิจ ทั้งระบบ\n- ความรู้ทั่วไป (GE) เพื่อพัฒนาทักษะชีวิต','YEAR 2: ความรู้พื้นฐาน\n- เรียนเกี่ยวกับกระบวนการทำงาน\n- ความรู้เบื