DROP TABLE IF EXISTS `minor_ext_subjects`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `minor_ext_subjects` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `minor_group_id` int(10) unsigned NOT NULL,
  `subject_code` varchar(20) NOT NULL,
  `name_th` varchar(300) NOT NULL,
  `name_en` varchar(300) NOT NULL DEFAULT '',
  `credits` varchar(10) NOT NULL DEFAULT '3',
  `subject_type` enum('required','elective') NOT NULL DEFAULT 'required',
  `special_note` varchar(300) NOT NULL DEFAULT '',
  `sort_order` smallint(5) unsigned NOT NULL DEFAULT 0,
  `is_active` tinyint(1) NOT NULL DEFAULT 1,
  PRIMARY KEY (`id`),
  KEY `fk_mes_group` (`minor_group_id`),
  CONSTRAINT `fk_mes_group` FOREIGN KEY (`minor_group_id`) REFERENCES `minor_groups` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=17 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
