INSERT INTO `mlos` VALUES ('4cdfb715-273d-11f1-9355-00090ffe0001','88bb7260-d3b0-472a-ad0a-818e279e9109','MLO3.1','ใช้แนวคิดการจัดการทรัพยากรมนุษย์ในการสร้างกิจกรรมเพื่อพัฒนาคน',1,'2026-03-24 11:52:46','2026-03-24 11:52:46'),('4ce09706-273d-11f1-9355-00090ffe0001','88bb7260-d3b0-472a-ad0a-818e279e9109','MLO3.2','ใช้เทคโนโลยีดิจิทัลในการบริหารทรัพยากรมนุษย์',2,'2026-03-24 11:52:46','2026-03-24 11:52:46'),('4ce1537c-273d-11f1-9355-00090ffe0001','c3fd5318-323d-44e1-82ea-d779325edf06','MLO4.1','วางแผนในการลดต้นทุนและเพิ่มกําไรโดยใช้ความรู้ด้านการจัดการโลจิสติกส์และโซ่อุปทานให้กับ\r\nธุรกิจ',1,'2026-03-24 11:52:46','2026-03-24 11:52:46'),('4ce1aab0-273d-11f1-9355-00090ffe0001','c3fd5318-323d-44e1-82ea-d779325edf06','MLO4.2','ประยุกต์ความรู้ทางด้านการจัดการโลจิสติกส์และโซ่อุปทานในการแก้ไขปัญหาของธุรกิจในฝั่ง\r\nOutbound และบริบทพื้นที่ภาคใต้',2,'2026-03-24 11:52:46','2026-03-24 11:52:46'),('4ce20c0d-273d-11f1-9355-00090ffe0001','5e5bd194-01a5-40d2-96ca-5debe0957c5e','MLO6.1','จัดงานไมซ์ได้ตามเป้าหมายการพัฒนาที่ยั่งยืน (SDGs) และสอดคล้องกับความต้องการของผู้มีส่วน\r\nได้ส่วนเสีย',1,'2026-03-24 11:52:46','2026-03-24 11:52:46'),('4ce28ba3-273d-11f1-9355-00090ffe0001','5e5bd194-01a5-40d2-96ca-5debe0957c5e','MLO6.2','ปรับตัวในสถานการณ์การจัดงานไมซ์ที่มีความกดดันและหาทางแก้ไขปัญหาผ่านความคิดสร้างสรรค์',2,'2026-03-24 11:52:46','2026-03-24 11:52:46'),('4ce2ec1d-273d-11f1-9355-00090ffe0001','199b640e-0b9c-40ec-b54f-bff320ef8fef','MLO2.1','วิเคราะห์กลยุทธ์ทางการตลาดอย่างสร้างสรรค์',1,'2026-03-24 11:52:46','2026-03-24 11:52:46'),('4ce3560f-273d-11f1-9355-00090ffe0001','199b640e-0b9c-40ec-b54f-bff320ef8fef','MLO2.2','วิเคราะห์แนวทางการแก้ไขปัญหาทางการตลาดเชิงนวัตกรรม',2,'2026-03-24 11:52:46','2026-03-24 11:52:46'),('4ce3966f-273d-11f1-9355-00090ffe0001','199b640e-0b9c-40ec-b54f-bff320ef8fef','MLO2.3','กําหนดกลยุทธ์การตลาดเพื่อใช้ในธุรกิจ',3,'2026-03-24 11:52:46','2026-03-24 11:52:46'),('4ce3dcbb-273d-11f1-9355-00090ffe0001','776d7a81-47a3-4fb5-b0b7-7ea0f05b7d02','MLO1.1','เขียนบทวิเคราะห์ตราสารทางการเงินภายใต้หลักเกณฑ์ของคณะกรรมการกํากับหลักทรัพย์และ\r\nตลาดหลักทรัพย์',1,'2026-03-24 11:52:46','2026-03-24 11:52:46'),('4ce41e68-273d-11f1-9355-00090ffe0001','776d7a81-47a3-4fb5-b0b7-7ea0f05b7d02','MLO1.2','วางแผนการเงินส่วนบุคคลตามมาตรฐานของสมาคมนักวางแผนการเงินไทย',2,'2026-03-24 11:52:46','2026-03-24 11:52:46'),('4ce4ce27-273d-11f1-9355-00090ffe0001','776d7a81-47a3-4fb5-b0b7-7ea0f05b7d02','MLO1.3','วิเคราะห์ข้อมูลทางการเงินเพื่อการบริหารการเงินขององค์กร',3,'2026-03-24 11:52:46','2026-03-24 11:52:46'),('4ce53e10-273d-11f1-9355-00090ffe0001','3d778ca6-3102-4f7f-876d-829def9cb34d','MLO5.1','พัฒนาระบบสารสนเทศทางธุรกิจเพื่อใช้ในการวางแผนธุรกิจ',1,'2026-03-24 11:52:46','2026-03-24 11:52:46'),('4ce58af3-273d-11f1-9355-00090ffe0001','3d778ca6-3102-4f7f-876d-829def9cb34d','MLO5.2','วางแผนและติดตั้งระบบสารสนเทศได้ถูกต้องตามกฎหมาย',2,'2026-03-24 11:52:46','2026-03-24 11:52:46');
