INSERT INTO `plo_score_structure` VALUES (1,'2567',1,'section',NULL,'ผลลัพธ์การเรียนรู้ระดับหลักสูตร (PLO)',NULL,NULL,'2026-03-15 10:25:37','2026-03-15 10:25:37'),(2,'2567',2,'row','PLO1','PLO1','พัฒนาตนเองจากการเรียนรู้เมื่อได้รับคำวิพากษ์วิจารณ์',NULL,'2026-03-15 10:25:37','2026-03-15 10:25:37'),(3,'2567',3,'row','PLO2','PLO2','วิเคราะห์และนำเสนอข้อมูลต่อผู้บริหารเพื่อการตัดสินใจ',NULL,'2026-03-15 10:25:37','2026-03-15 10:25:37'),(4,'2567',4,'row','PLO3','PLO3','ประยุกต์ความรู้ด้านบริหารธุรกิจเพื่อวางแผนกลยุทธ์ให้องค์กร',NULL,'2026-03-15 10:25:37','2026-03-15 10:25:37'),(5,'2567',5,'row','PLO4','PLO4','ประยุกต์กรอบแนวคิดความเป็นผู้ประกอบการเพื่อการสร้างธุรกิจ',NULL,'2026-03-15 10:25:37','2026-03-15 10:25:37'),(6,'2567',6,'row','PLO5','PLO5','ประยุกต์ใช้กระบวนการวิจัยเพื่อแก้ไขปัญหาทางธุรกิจ',NULL,'2026-03-15 10:25:37','2026-03-15 10:25:37'),(7,'2567',7,'row','PLO6','PLO6','สื่อสารภายใต้ความหลากหลายทางสังคมและวัฒนธรรม',NULL,'2026-03-15 10:25:37','2026-03-15 10:25:37'),(8,'2567',8,'row','PLO7','PLO7','ทำงานร่วมกับผู้อื่นในองค์กร',NULL,'2026-03-15 10:25:37','2026-03-15 10:25:37'),(9,'2567',9,'row','PLO8','PLO8','เลือกใช้เทคโนโลยีดิจิทัลในการทำงานให้บรรลุเป้าหมาย',NULL,'2026-03-15 10:25:37','2026-03-15 10:25:37'),(10,'2567',10,'row','PLO9','PLO9','แสดงพฤติกรรมที่แสดงถึงการมีจริยธรรมและความรับผิดชอบต่อสังคม',NULL,'2026-03-15 10:25:37','2026-03-15 10:25:37'),(11,'2567',11,'subtotal',NULL,'รวม PLO หลักสูตรบริหารธุรกิจ',NULL,'ba','2026-03-15 10:25:37','2026-03-15 10:25:37'),(12,'2567',12,'section',NULL,'ผลลัพธ์การเรียนรู้ระดับวิชาเอก (MLO)',NULL,NULL,'2026-03-15 10:25:37','2026-03-15 10:25:37'),(13,'2567',13,'row','MLO1.1','MLO1.1','เขียนบทวิเคราะห์ตราสารทางการเงินภายใต้หลักเกณฑ์ของ กลต.',NULL,'2026-03-15 10:25:37','2026-03-15 10:25:37'),(14,'2567',14,'row','MLO1.2','MLO1.2','วางแผนการเงินส่วนบุคคลตามมาตรฐานของสมาคมนักวางแผนการเงินไทย',NULL,'2026-03-15 10:25:37','2026-03-15 10:25:37'),(15,'2567',15,'row','MLO1.3','MLO1.3','วิเคราะห์ข้อมูลทางการเงินเพื่อการบริหารการเงินของ