DROP TABLE IF EXISTS `plo_scores`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `plo_scores` (
  `id` char(36) NOT NULL DEFAULT uuid(),
  `program_id` char(36) NOT NULL,
  `dept_name` varchar(100) DEFAULT NULL,
  `group_name` varchar(100) DEFAULT NULL,
  `lo_level` enum('PLO','MLO','CLO') NOT NULL,
  `lo_code` text NOT NULL,
  `lo_description` text DEFAULT NULL,
  `academic_year` int(11) NOT NULL,
  `semester_1` decimal(4,2) DEFAULT NULL,
  `semester_2` decimal(4,2) DEFAULT NULL,
  `note` text DEFAULT NULL,
  `sort_order` int(11) DEFAULT 0,
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  `updated_at` datetime NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_prog_level_code_year` (`program_id`,`lo_level`,`lo_code`,`academic_year`) USING HASH,
  KEY `idx_plo_scores_prog_year` (`program_id`,`academic_year`),
  CONSTRAINT `fk_ps_prog` FOREIGN KEY (`program_id`) REFERENCES `programs` (`id`) ON DELETE CASCADE,
  CONSTRAINT `chk_sem1` CHECK (`semester_1` between 0 and 5),
  CONSTRAINT `chk_sem2` CHECK (`semester_2` between 0 and 5)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
