DROP TABLE IF EXISTS `plos`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `plos` (
  `id` char(36) NOT NULL DEFAULT uuid(),
  `program_id` char(36) NOT NULL,
  `code` text NOT NULL,
  `description` text NOT NULL,
  `sort_order` int(11) NOT NULL DEFAULT 0,
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  `updated_at` datetime NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_plo` (`program_id`,`code`(20)),
  UNIQUE KEY `uq_program_code` (`program_id`,`code`) USING HASH,
  KEY `idx_plos_program` (`program_id`),
  CONSTRAINT `fk_plo_prog` FOREIGN KEY (`program_id`) REFERENCES `programs` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
