INSERT INTO `plos` VALUES ('4cdd99cb-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','PLO1','พัฒนาตนเองจากการเรียนรู้เมื่อได้รับคำวิพากษ์วิจารณ์',1,'2026-03-24 11:52:46','2026-03-24 11:52:46'),('4cddae92-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','PLO2','วิเคราะห์และนำเสนอข้อมูลต่อผู้บริหารเพื่อการตัดสินใจ',2,'2026-03-24 11:52:46','2026-03-24 11:52:46'),('4cddc0ec-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','PLO3','ประยุกต์ความรู้ทางด้านบริหารธุรกิจเพื่อวางแผนกลยุทธ์ให้องค์กร',3,'2026-03-24 11:52:46','2026-03-24 11:52:46'),('4cddd1ee-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','PLO4','ประยุกต์กรอบแนวคิดความเป็นผู้ประกอบการ (Entrepreneurial Mindset) เพื่อการสร้างธุรกิจ',4,'2026-03-24 11:52:46','2026-03-24 11:52:46'),('4cdde1d9-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','PLO5','ประยุกต์ใช้กระบวนการวิจัยเพื่อแก้ไขปัญหาทางธุรกิจ',5,'2026-03-24 11:52:46','2026-03-24 11:52:46'),('4cddf15f-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','PLO6','สื่อสารภายใต้ความหลากหลายทางสังคมและวัฒนธรรม',6,'2026-03-24 11:52:46','2026-03-24 11:52:46'),('4cde00ba-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','PLO7','ทำงานร่วมกับผู้อื่นในองค์กร',7,'2026-03-24 11:52:46','2026-03-24 11:52:46'),('4cde10b2-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','PLO8','เลือกใช้เทคโนโลยีดิจิทัลในการทำงานให้บรรลุเป้าหมาย',8,'2026-03-24 11:52:46','2026-03-24 11:52:46'),('4cde2bc8-273d-11f1-9355-00090ffe0001','00000000-0000-0000-0000-000000000001','PLO9','แสดงพฤติกรรมที่แสดงถึงการมีจริยธรรมและความรับผิดชอบต่อสังคม',9,'2026-03-24 11:52:46','2026-03-24 11:52:46'),('736063a0-2299-11f1-a590-00090ffe0001','00000000-0000-0000-0000-000000000002','PLO1','มีทักษะและความรู้พื้นฐานทางด้านเทคโนโลยี\r\nสารสนเทศ สามารถติดตั้งและจัดการระบบ\r\nคอมพิวเตอร์ให้สามารถใช้งานได้อย่างต่อเนื่อง',6,'2026-03-18 14:09:48','2026-03-21 23:08:30'),('736184e6-2299-11f1-a590-00090ffe0001','00000000-0000-0000-0000-000000000002','PLO2','มีความเข้าใจและสามารถวิเคราะห์ระบบสำหรับ\r\nองค์กรและออกแบบระบบฐานข้อมูลสำหรับระบบ\r\nสารสนเทศเพื่อการจัดการ',7,'2026-03-18 14:09:48','2026-03-21 23:08:31'),('7362e826-2299-11f1-a590-00090ffe0001','00000000-0000-0000-0000-000000000002','PLO3','มีความเข้าใจและสามารถวิเคราะห์และออกแบบ\r\nระบบเครือข่ายคอมพิวเตอร์และความมั่นคงของ\r\nระบบสารสนเทศ',8,'2026-03-18 14:09:48','2026-03-21 23:08:31'),('736413a8-2299-11f1-a590-00090ffe0001','00000000-0000-0000-0000-000000000002','PLO4','มีความเข้าใจหลักการการบริหารจัดการและ\r\nสามารถบูรณาการองค์ความรู้ทางบริหารธุรกิจและ\r\nเทคโนโลยีสารสนเทศได้อย่างเหมาะสม',1,'2026-03-18 14:09:48','2026-03-21 23:08:30'),('7364eb24-2299-11f1-a590-00090ffe0001','00000000-0000-0000-0000-000000000002','PLO5','สามารถประยุกต์ใช้ซอฟต์แวร์เพื่อการบริหาร\r\nจัดการทางธุรกิจได้อย่างเหมาะสม',2,'2026-03-18 14:09:48','2026-03-21 23:08:30'),('73669137-2299-11f1-a590-00090ffe0001','00000000-0000-0000-0000-000000000002','PLO6','มีความสามารถในการพัฒนาโปรแกรมสําหรับงาน\r\nธุรกิจที่สามารถทำงานบนอุปกรณ์คอมพิวเตอร์ \r\nอุปกรณ์พกพาและเว็บ',9,'2026-03-18 14:09:48','2026-03-21 23:08:31'),('7367e971-2299-11f1-a590-00090ffe0001','00000000-0000-0000-0000-000000000002','PLO7','สามารถพัฒนาโครงงานทางระบบสารสนเทศโดย\r\nใช้กระบวนการวิจัยเป็นฐาน',10,'2026-03-18 14:09:48','2026-03-21 23:08:31'),('73692ddb-2299-11f1-a590-00090ffe0001','00000000-0000-0000-0000-000000000002','PLO8','มีทักษะด้านภาวะผู้นำ และความรับผิดชอบ \r\nตลอดจนมีวินัยในตนเอง',3,'2026-03-18 14:09:48','2026-03-21 23:08:30'),('736a140f-2299-11f1-a590-00090ffe0001','00000000-0000-0000-0000-000000000002','PLO9','มีจรรยาบรรณ และจริยธรรมวิชาชีพ',4,'2026-03-18 14:09:48','2026-03-21 23:08:30'),('736b6eec-2299-11f1-a590-00090ffe0001','00000000-0000-0000-0000-000000000002','PLO10','มีความรู้และทักษะทั่วไปด้านภาษาต่างประเทศ \r\nการใช้ชีวิตในสังคม กีฬาและนันทนาการ และการ\r\nคิดวิเคราะห์เชิงตัวเลข',5,'2026-03-18 14:09:48','2026-03-21 23:08:30');
/*!40000 ALTER TABLE `plos` ENABLE KEYS */;
