CREATE TABLE `semester_subjects` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `semester_id` int(11) NOT NULL,
  `subject_id` int(11) NOT NULL,
  `category` varchar(30) NOT NULL DEFAULT 'Core',
  `credits` int(11) DEFAULT NULL,
  `hour_structure` varchar(50) DEFAULT NULL,
  `sort_order` int(11) NOT NULL DEFAULT 1,
  `name_th` text DEFAULT NULL COMMENT 'override ชื่อวิชาตามหลักสูตร ถ้า NULL ให้ใช้ชื่อจาก subjects.name_th',
  PRIMARY KEY (`id`),
  KEY `idx_sem_subjects_sem` (`semester_id`),
  KEY `idx_sem_subjects_subj` (`subject_id`),
  CONSTRAINT `fk_semsubj_sem` FOREIGN KEY (`semester_id`) REFERENCES `semesters` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_semsubj_subj` FOREIGN KEY (`subject_id`) REFERENCES `subjects` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=5155 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
