CREATE TABLE `semesters` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `study_plan_id` int(11) NOT NULL,
  `term_no` int(11) NOT NULL,
  `title` text DEFAULT NULL,
  `total_credits` int(11) NOT NULL DEFAULT 0,
  `sort_order` int(11) NOT NULL DEFAULT 1,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_semester` (`study_plan_id`,`term_no`),
  KEY `idx_semesters_plan` (`study_plan_id`),
  CONSTRAINT `fk_sem_plan` FOREIGN KEY (`study_plan_id`) REFERENCES `study_plans` (`id`) ON DELETE CASCADE,
  CONSTRAINT `chk_term_no` CHECK (`term_no` in (1,2,3))
) ENGINE=InnoDB AUTO_INCREMENT=1254 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
