  CONSTRAINT `fk_spm_survey` FOREIGN KEY (`survey_id`) REFERENCES `stakeholder_surveys` (`id`) ON DELETE CASCADE,
  CONSTRAINT `chk_spm_level` CHECK (`level` in ('F','M','P'))
