INSERT INTO `student_page_content` VALUES (1,10,'{\"general\":{\"title_th\":\"หมวดวิชาศึกษาทั่วไป\",\"title_en\":\"General Education\",\"subtitle\":\"General Education — คลิกเพื่อดูรายละเอียด\",\"content\":\"เลือกจากรายวิชาเลือกของหมวดวิชาศึกษาทั่วไปที่เปิดสอนในมหาวิทยาลัยสงขลานครินทร์ ทั้งนี้ต้องตรงตามปริญญาของหมวดวิชาศึกษาทั่วไปซึ่งผ่านความเห็นชอบจากคณะกรรมการพัฒนาหมวดวิชาศึกษาทั่วไปของมหาวิทยาลัยสงขลานครินทร์\",\"btn_text\":\"ดูรายวิชาเลือก มอ. หาดใหญ่\",\"btn_url\":\"https://gened.psu.ac.th/category/hatyai/\"},\"free\":{\"title_th\":\"หมวดวิชาเลือกเสรี\",\"title_en\":\"Free Elective\",\"subtitle\":\"Free Elective — คลิกเพื่อดูรายละเอียด\",\"content\":\"นักศึกษาสามารถเลือกเรียนรายวิชาใด ๆ ที่สนใจที่เปิดสอนในมหาวิทยาลัยสงขลานครินทร์ หรือ มหาวิทยาลัยอื่นทั้งในประเทศและต่างประเทศ โดยความเห็นชอบของหลักสูตร/วิชาเอก\"},\"specific\":{\"title_th\":\"หมวดวิชาเฉพาะ\",\"title_en\":\"Specific Courses\",\"subtitle\":\"Specific Courses — ประกอบด้วยหมวดย่อย 4 ประเภท\"}}','{\"text\":\"วิชาโท เลือกได้จากกลุ่มวิชาใดกลุ่มหนึ่ง รวม 15 หน่วยกิต\",\"bold_text\":\"วิชาบังคับและวิชาเลือกของแต่ละวิชาเอกสามารถนำมานับเป็นวิชาโทได้ทั้งหมด\"}','2026-03-25 03:01:53'),(6,3,'{\"general\":{\"title_th\":\"หมวดวิชาศึกษาทั่วไป\",\"title_en\":\"General Education\",\"subtitle\":\"General Education — คลิกเพื่อดูรายละเอียด\",\"content\":\"เลือกจากรายวิชาเลือกของหมวดวิชาศึกษาทั่วไปที่เปิดสอนในมหาวิทยาลัยสงขลานครินทร์ ทั้งนี้ต้องตรงตามปริญญาของหมวดวิชาศึกษาทั่วไปซึ่งผ่านความเห็นชอบจากคณะกรรมการพัฒนาหมวดวิชาศึกษาทั่วไปของมหาวิทยาลัยสงขลานครินทร์\",\"btn_text\":\"ดูรายวิชาเลือก มอ. หาดใหญ่\",\"btn_url\":\"https://gened.psu.ac.th/category/hatyai/\"},\"free\":{\"title_th\":\"หมวดวิชาเลือกเสรี\",\"title_en\":\"Free Elective\",\"subtitle\":\"Free Elective — คลิกเพื่อดูรายละเอียด\",\"content\":\"นักศึกษาสามารถเลือกเรียนรายวิชาใด ๆ ที่สนใจที่เปิดสอนในมหาวิทยาลัยสงขลานครินทร์ หรือ มหาวิทยาลัยอื่นทั้งในประเทศและต่างประเทศ โดยความเห็นชอบของหลักสูตร/วิชาเอก\"},\"specific\":{\"title_th\":\"หมวดวิชาเฉพาะ\",\"title_en\