DROP TABLE IF EXISTS `subjects`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `subjects` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `course_id` int(11) DEFAULT NULL,
  `code` varchar(50) NOT NULL,
  `name_th` text NOT NULL,
  `name_en` text DEFAULT NULL,
  `default_credits` int(11) NOT NULL,
  `default_hour_structure` varchar(50) DEFAULT NULL,
  `description_th` text DEFAULT NULL,
  `description_en` text DEFAULT NULL,
  `outcomes_th` text DEFAULT NULL,
  `outcomes_en` text DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_subject_code_per_course` (`course_id`,`code`),
  KEY `idx_subjects_course_id` (`course_id`),
  KEY `idx_subjects_course` (`course_id`),
  CONSTRAINT `fk_subjects_course` FOREIGN KEY (`course_id`) REFERENCES `courses` (`id`) ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1732 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

