INSERT INTO `subjects` VALUES (273,3,'GE-001','บังคับกลุ่มสาระภาษาและการสื่อสาร*',NULL,2,'2((2)-0-4)','เป็นไปตามประกาศมหาวิทยาลัย เรื่อง เกณฑ์การเรียนรายวิชาศึกษาทั่วไปสาระบังคับเรียน',NULL,NULL,NULL),(274,3,'ELEC-004','วิชาชีพเลือก',NULL,3,NULL,'เลือกตามความสนใจ',NULL,NULL,NULL),(275,3,'ELEC-006','วิชาชีพเลือก หรือ วิชาโท',NULL,3,NULL,'เลือกตามความสนใจ',NULL,NULL,NULL),(276,3,'ELEC-007','วิชาชีพเลือก หรือวิชาโท',NULL,3,NULL,'เลือกตามความสนใจ',NULL,NULL,NULL),(277,3,'ELEC-001','วิชาเลือกเสรี',NULL,3,NULL,'เลือกตามความสนใจ',NULL,NULL,NULL),(278,3,'ELEC-003','วิชาโท',NULL,3,NULL,'เลือกตามความสนใจ',NULL,NULL,NULL),(279,3,'ELEC-002','วิชาโท หรือ วิชาชีพเลือก',NULL,3,NULL,'เลือกตามความสนใจ',NULL,NULL,NULL),(280,3,'ELEC-005','วิชาโท หรือ วิชาเลือกเสรี',NULL,3,NULL,'เลือกตามความสนใจ',NULL,NULL,NULL),(281,3,'GE-004','เลือกการคิดเชิงระบบ',NULL,2,'2((2)-0-4)','เลือกตามความสนใจ',NULL,NULL,NULL),(282,3,'GE-003','เลือกการรู้ดิจิทัล',NULL,2,'2((2)-0-4)','เลือกตามความสนใจ',NULL,NULL,NULL),(283,3,'GE-006','เลือกการอยู่อย่างเท่าทัน',NULL,2,'2((2)-0-4)','เลือกตามความสนใจ',NULL,NULL,NULL),(284,3,'GE-005','เลือกสุนทรียศาสตร์และกีฬา',NULL,1,'1((1)-0-2)','เลือกตามความสนใจ',NULL,NULL,NULL),(285,3,'GE-002','เลือกหมวดวิชาศึกษาทั่วไป',NULL,2,'2((2)-0-4)','เลือกตามความสนใจ',NULL,NULL,NULL),(1491,3,'460-102','การจัดการทรัพยากรมนุษย์',NULL,3,'3((3)-0-6)','ภาพรวมการจัดการทรัพยากรมนุษย์ การจัดสายงาน การวางแผนกําลังคน การสรรหา การคัดเลือก การฝึกอบรมพนักงาน',NULL,NULL,NULL),(1494,3,'460-105','การจัดการทรัพยากรมนุษย์',NULL,3,'3((3)-0-6)','ภาพรวมการจัดการทรัพยากรมนุษย์ การจัดสายงาน การวางแผนกําลังคน การสรรหา การคัดเลือก การฝึกอบรมพนักงาน',NULL,NULL,NULL),(1496,3,'460-202','ชุดวิชาดิจิทัล นวัตกรรม และความเป็นผู้ประกอบการ',NULL,7,'7((3)-8-10)','แนวคิดพื้นฐานสถาปัตยกรรมอัจฉริยะทางธุรกิจ ภาพรวมของวงจรชีวิตโครงงานอัจฉริยะทางธุรกิจ',NULL,NULL,NULL),(1498,3,'460-302','สถิติสําหรับการวิจัยทางธุรกิจ',NULL,3,'3((2)-2-5)','เครื่องมือพื้นฐานทางสถิติ การวัดแนวโน้มเข้าสู่ส่วนกลาง การสํารวจด้วยตัวอย่าง การแจกแจงปกต