DROP TABLE IF EXISTS `survey_mappings`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `survey_mappings` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `survey_id` char(36) NOT NULL,
  `source` varchar(100) NOT NULL,
  `target` varchar(100) NOT NULL,
  `value` varchar(10) DEFAULT NULL,
  `weight` int(11) DEFAULT 1,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_survey_mapping` (`survey_id`,`source`,`target`),
  UNIQUE KEY `uq_sm_survey_source_target` (`survey_id`,`source`,`target`),
  KEY `idx_survey_id` (`survey_id`),
  CONSTRAINT `fk_survey_mappings_surveys` FOREIGN KEY (`survey_id`) REFERENCES `surveys` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
